/**
 * @numkeys/rp-sdk — Relying-Party SDK for Numkeys Protocol v1.2.
 *
 * This package wraps the Numkeys protocol primitives with one-call ergonomic
 * helpers for the two browser transports defined in SPEC.md §9.5:
 *
 *   - `openVerifyPopup`        — popup + postMessage round-trip
 *   - `consumeRedirectFragment` — parse the location.hash response on
 *                                  page load after a redirect-transport
 *                                  return.
 *
 * Both helpers run the full SPEC §9.9 verifier on the response before
 * returning, so a successful resolution is always a verified result.
 *
 * The SDK does not bundle any opinionated transport defaults that would
 * compromise SPEC compliance. In particular, RPs must always supply:
 *
 *   - `allowedIssuers`   — the issuer iss values you trust (SSRF defense
 *                           runs before any network fetch).
 *   - `getIssuerPubkey`  — your TLS+caching+SSRF-safe pubkey resolver.
 *   - `nonceStore`       — defaults to the protocol's `InMemoryNonceStore`
 *                           which is process-local and NOT safe for
 *                           multi-instance deployments.
 *
 * For server-side verification (e.g. Node express handler) call
 * `verifyRpVerifyResponse` directly — re-exported below — and pair it
 * with a Redis- or DB-backed `NonceStore`.
 */

import {
  buildRpVerifyRequest,
  encodeRpVerifyRequest,
  verifyRpVerifyResponse,
  InMemoryNonceStore,
  RpVerifyResponseSchema,
  RpVerifyErrorResponseSchema,
  bytesToB64Url,
  b64UrlToBytes,
  canonicalJson,
  ProtocolError,
  WALLET_SDK_CONTRACT_VERSION,
  NUMKEYS_PROTOCOL_VERSION,
  type RpVerifyRequest,
  type RpVerifyResponse,
  type RpVerifyErrorResponse,
  type RpScope,
  type IssuerPubkeyResolver,
  type NonceStore,
  type VerifyRpResponseOptions,
  type VerifyRpResponseResult,
} from "@workspace/numkeys-protocol";

// Re-export everything an RP integrator is likely to need.
export {
  buildRpVerifyRequest,
  encodeRpVerifyRequest,
  verifyRpVerifyResponse,
  InMemoryNonceStore,
  ProtocolError,
  WALLET_SDK_CONTRACT_VERSION,
  NUMKEYS_PROTOCOL_VERSION,
};
export type {
  RpVerifyRequest,
  RpVerifyResponse,
  RpVerifyErrorResponse,
  RpScope,
  IssuerPubkeyResolver,
  NonceStore,
  VerifyRpResponseOptions,
  VerifyRpResponseResult,
};

// ── openVerifyPopup ───────────────────────────────────────────────────────

export interface OpenVerifyPopupParams {
  /**
   * The wallet's verify URL, e.g. "https://numkeys.com/wallet/verify".
   * The SDK appends `?req=<encoded>` itself.
   */
  walletUrl: string;
  /** RP origin shown to the user and bound into the signed response. */
  rpOrigin: string;
  /** Human-readable name shown prominently in the consent UI. */
  rpName: string;
  scope: RpScope;
  /** REQUIRED if `scope === "phone"`. E.164 format ("+15551234567"). */
  candidatePhoneE164?: string;
  /** Request lifetime in seconds (default 120, max 300). */
  ttlSec?: number;
  /** Issuer iss values your application trusts. SSRF allow-list. */
  allowedIssuers: string[];
  /**
   * Resolves an issuer's Ed25519 public key (b64url). Implementations
   * MUST do their own SSRF protection, TLS validation, and caching.
   * Returning null triggers `issuer_key_discovery_failed`.
   */
  getIssuerPubkey: IssuerPubkeyResolver;
  /** Defaults to a per-call InMemoryNonceStore. Not safe across instances. */
  nonceStore?: NonceStore;
  /** Reject attestations older than this. Default 365 days. */
  maxAttestationAgeSec?: number;
  /** Tolerance for response.iat in the future (default 60). */
  clockSkewSec?: number;
  /** window.open features. Default "popup,width=480,height=720". */
  popupFeatures?: string;
  /** Total timeout in ms before rejecting with "timeout". Default 5min. */
  timeoutMs?: number;
  /** Window object override (for tests). Defaults to `window`. */
  windowRef?: Window;
}

/** Result type for `openVerifyPopup` — popup-transport reasons included. */
export type OpenVerifyPopupResult =
  | { ok: true; result: VerifyRpResponseResult; response: RpVerifyResponse }
  | { ok: false; reason: "declined"; error: string }
  | { ok: false; reason: "verification_failed"; error: string }
  | { ok: false; reason: "timeout" }
  | { ok: false; reason: "popup_blocked" }
  | { ok: false; reason: "popup_closed" };

/**
 * Result type for `consumeRedirectFragment` — strictly the reasons
 * reachable on a fragment-return page load. Excludes popup-only
 * conditions (popup_blocked / popup_closed / timeout) for typing clarity.
 */
export type ConsumeRedirectResult =
  | { ok: true; result: VerifyRpResponseResult; response: RpVerifyResponse }
  | { ok: false; reason: "declined"; error: string }
  | { ok: false; reason: "verification_failed"; error: string };

/**
 * Open the wallet popup, build a signed request, await the postMessage
 * response, run the full SPEC §9.9 verifier, and resolve with the result.
 *
 * The promise NEVER rejects with a thrown error in normal flow — every
 * failure is encoded into the discriminated union for explicit handling.
 */
export async function openVerifyPopup(
  params: OpenVerifyPopupParams,
): Promise<OpenVerifyPopupResult> {
  const w = params.windowRef ?? (globalThis as { window?: Window }).window;
  if (!w) throw new Error("openVerifyPopup requires a browser window.");

  const request = buildRpVerifyRequest({
    rpOrigin: params.rpOrigin,
    rpName: params.rpName,
    scope: params.scope,
    candidatePhoneE164: params.candidatePhoneE164 ?? null,
    ttlSec: params.ttlSec,
  });
  const encoded = encodeRpVerifyRequest(request);
  const url = new URL(params.walletUrl);
  url.searchParams.set("req", encoded);

  const popup = w.open(
    url.toString(),
    "numkeys-verify",
    params.popupFeatures ?? "popup,width=480,height=720",
  );
  if (!popup) return { ok: false, reason: "popup_blocked" };

  const walletOrigin = new URL(params.walletUrl).origin;
  const nonceStore = params.nonceStore ?? new InMemoryNonceStore();

  return new Promise<OpenVerifyPopupResult>((resolve) => {
    let settled = false;
    const settle = (r: OpenVerifyPopupResult) => {
      if (settled) return;
      settled = true;
      w.removeEventListener("message", onMessage);
      clearInterval(closedPoll);
      clearTimeout(timer);
      resolve(r);
    };

    const onMessage = async (ev: MessageEvent) => {
      // SPEC §9.5.1: RP MUST verify event.origin matches the wallet origin.
      if (ev.origin !== walletOrigin) return;
      const data = ev.data as { type?: string; response?: unknown };
      if (data?.type !== "numkeys/verify-response") return;

      const okParse = RpVerifyResponseSchema.safeParse(data.response);
      const errParse = RpVerifyErrorResponseSchema.safeParse(data.response);
      if (errParse.success) {
        if (errParse.data.request_id !== request.request_id) return;
        settle({ ok: false, reason: "declined", error: errParse.data.error });
        return;
      }
      if (!okParse.success) {
        settle({
          ok: false,
          reason: "verification_failed",
          error: "Malformed message from wallet",
        });
        return;
      }
      if (okParse.data.request_id !== request.request_id) return;

      try {
        const result = await verifyRpVerifyResponse({
          request,
          response: okParse.data,
          options: {
            allowedIssuers: params.allowedIssuers,
            maxAttestationAgeSec:
              params.maxAttestationAgeSec ?? 60 * 60 * 24 * 365,
            clockSkewSec: params.clockSkewSec ?? 60,
          },
          getIssuerPubkey: params.getIssuerPubkey,
          nonceStore,
        });
        settle({ ok: true, result, response: okParse.data });
      } catch (e) {
        const msg =
          e instanceof ProtocolError
            ? `${e.code}: ${e.message}`
            : (e as Error).message;
        settle({ ok: false, reason: "verification_failed", error: msg });
      }
    };

    w.addEventListener("message", onMessage);

    const closedPoll = setInterval(() => {
      if (popup.closed) settle({ ok: false, reason: "popup_closed" });
    }, 500);

    const timer = setTimeout(
      () => {
        try {
          popup.close();
        } catch {
          /* popup may already be closed */
        }
        settle({ ok: false, reason: "timeout" });
      },
      params.timeoutMs ?? 5 * 60 * 1000,
    );
  });
}

// ── consumeRedirectFragment ───────────────────────────────────────────────

export interface ConsumeRedirectFragmentParams {
  /**
   * The original request that was sent to the wallet. The RP MUST persist
   * this between the outbound navigation and the inbound return — the
   * verifier needs `nonce`, `request_id`, `rp_origin`, etc. to bind.
   */
  request: RpVerifyRequest;
  allowedIssuers: string[];
  getIssuerPubkey: IssuerPubkeyResolver;
  nonceStore?: NonceStore;
  maxAttestationAgeSec?: number;
  clockSkewSec?: number;
  /** Defaults to `window.location.hash`. */
  hash?: string;
  /** If true, replace history entry to clear the fragment. Default true. */
  clearHash?: boolean;
  windowRef?: Window;
}

/**
 * Inspect `window.location.hash` for a `numkeys_response=...` fragment
 * left by the wallet's redirect transport (SPEC §9.5.2). Returns null if
 * no response is present (typical first-page-load), or the verified
 * result / failure information if one is.
 */
export async function consumeRedirectFragment(
  params: ConsumeRedirectFragmentParams,
): Promise<ConsumeRedirectResult | null> {
  const w = params.windowRef ?? (globalThis as { window?: Window }).window;
  const hash = params.hash ?? w?.location.hash ?? "";
  const trimmed = hash.startsWith("#") ? hash.slice(1) : hash;
  if (!trimmed) return null;
  const usp = new URLSearchParams(trimmed);
  const encoded = usp.get("numkeys_response");
  if (!encoded) return null;

  // Best-effort hash clearing so a refresh doesn't replay the response
  // (defense-in-depth — the verifier's nonce store is the real replay guard).
  if (w && (params.clearHash ?? true)) {
    try {
      const url = new URL(w.location.href);
      url.hash = "";
      w.history.replaceState(null, "", url.toString());
    } catch {
      /* ignore */
    }
  }

  let raw: unknown;
  try {
    raw = JSON.parse(new TextDecoder().decode(b64UrlToBytes(encoded)));
  } catch {
    return {
      ok: false,
      reason: "verification_failed",
      error: "fragment is not valid b64url canonical JSON",
    };
  }

  const okParse = RpVerifyResponseSchema.safeParse(raw);
  const errParse = RpVerifyErrorResponseSchema.safeParse(raw);
  if (errParse.success) {
    if (errParse.data.request_id !== params.request.request_id) {
      return {
        ok: false,
        reason: "verification_failed",
        error: "request_id mismatch on redirect fragment",
      };
    }
    return { ok: false, reason: "declined", error: errParse.data.error };
  }
  if (!okParse.success) {
    return {
      ok: false,
      reason: "verification_failed",
      error: okParse.error.message,
    };
  }
  const nonceStore = params.nonceStore ?? new InMemoryNonceStore();
  try {
    const result = await verifyRpVerifyResponse({
      request: params.request,
      response: okParse.data,
      options: {
        allowedIssuers: params.allowedIssuers,
        maxAttestationAgeSec:
          params.maxAttestationAgeSec ?? 60 * 60 * 24 * 365,
        clockSkewSec: params.clockSkewSec ?? 60,
      },
      getIssuerPubkey: params.getIssuerPubkey,
      nonceStore,
    });
    return { ok: true, result, response: okParse.data };
  } catch (e) {
    const msg =
      e instanceof ProtocolError ? `${e.code}: ${e.message}` : (e as Error).message;
    return { ok: false, reason: "verification_failed", error: msg };
  }
}

// Internal re-exports used by SDK helpers themselves; not part of the
// public surface but harmless to expose.
export { bytesToB64Url, b64UrlToBytes, canonicalJson };
